@import "tailwindcss";

@theme {
  /* palette (mined, ranked by usage) */
  --color-neutral-50: #ffffff;
  --color-neutral-100: #f3f3f3;
  --color-neutral-200: #dfdfdf;
  --color-neutral-300: #cecece;
  --color-neutral-400: #c1c0c0;
  --color-neutral-500: #afafaf;
  --color-neutral-600: #8f8f8f;
  --color-neutral-700: #767676;
  --color-neutral-800: #5d5d5d;
  --color-neutral-900: #414141;
  --color-neutral-950: #303030;
  --color-cyan: #0285ff;
  --color-red: #fa423e;
  --color-blue: #7d5bff;
  --color-blue-2: #aa96ff;
  --color-blue-3: #5856d6;
  --color-teal: #10a37f;
  --color-blue-4: #4e86f7;
  --color-deep-blue: #0f172a;
  --color-yellow: #f2c94c;
  --color-orange: #c76b12;
  --color-red-2: #e02e2a;
  --color-blue-5: #6157ff;

  /* inferred semantic roles (each maps to a distinct mined value) */
  --color-canvas: #ffffff;
  --color-ink: #303030;
  --color-text-muted: #afafaf;
  --color-surface: #f3f3f3;
  --color-hairline: #dfdfdf;
  --color-accent: #0285ff;
  --color-accent-2: #fa423e;
  --color-accent-3: #7d5bff;

  --font-sans: "OpenAI Sans", ui-sans-serif, system-ui, sans-serif;
  --font-mono: "Atkinson Hyperlegible Mono", ui-monospace, monospace;

  --text-xs: 0.5rem;
  --text-sm: 0.625rem;
  --text-base: 0.6875rem;
  --text-lg: 0.75rem;
  --text-xl: 0.856875rem;
  --text-2xl: 0.875rem;
  --text-3xl: 0.9rem;
  --text-4xl: 1rem;
  --text-5xl: 1.0625rem;
  --text-6xl: 1.25rem;
  --text-7xl: 1.5rem;
  --text-8xl: 2.25rem;

  --font-weight-light: 300;
  --font-weight-normal: 400;
  --font-weight-medium: 500;
  --font-weight-510: 510;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  /* line-heights, sorted tight -> loose */
  --leading-none: 1;
  --leading-tight: 1.33;
  --leading-snug: 1.4;
  --leading-normal: 1.43;
  --leading-relaxed: 1.45;
  --leading-loose: 1.5;
  --leading-looser: 1.6;
  --leading-loosest: 1.71;

  /* letter-spacing, sorted tight -> wide */
  --tracking-tightest: -.026875rem;
  --tracking-tighter: -.015em;
  --tracking-tight: -.18px;
  --tracking-normal: -.154px;
  --tracking-wide: -.08px;
  --tracking-wider: -.005rem;

  --radius-sm: .25rem;
  --radius-md: .375rem;
  --radius-lg: 10px;
  --radius-xl: 18px;
  --radius-2xl: 1.25rem;
  --radius-3xl: 26px;
  --radius-4xl: 100%;
  --radius-full: 50%;

  /* shadows, sorted by blur */
  --shadow-sm: 0 1px #0000;
  --shadow-md: 0 -1px #0000;
  --shadow-lg: 0 2px 8px #0000000d;

  --breakpoint-sm: 30rem;
  --breakpoint-md: 40rem;
  --breakpoint-lg: 48rem;
  --breakpoint-xl: 64rem;
  --breakpoint-2xl: 80rem;
  --breakpoint-3xl: 96rem;

